import{_ as o,C as r,o as t,c as s,a2 as a,b as d,w as n,a as l,E as c,a3 as p}from"./chunks/framework.B72_uj9U.js";const k=JSON.parse('{"title":"SageAgent — Unique Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/sage-agent/unique-patterns.md","filePath":"research/agents/sage-agent/unique-patterns.md"}'),h={name:"research/agents/sage-agent/unique-patterns.md"};function g(u,e,m,f,b,_){const i=r("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="sageagent-—-unique-patterns" tabindex="-1">SageAgent — Unique Patterns <a class="header-anchor" href="#sageagent-—-unique-patterns" aria-label="Permalink to &quot;SageAgent — Unique Patterns&quot;">​</a></h1><h2 id="_1-dual-execution-modes" tabindex="-1">1. Dual Execution Modes <a class="header-anchor" href="#_1-dual-execution-modes" aria-label="Permalink to &quot;1. Dual Execution Modes&quot;">​</a></h2><p>SageAgent offers two distinct modes of operation:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Pipeline</th><th>Feedback Loop</th><th>Use Case</th></tr></thead><tbody><tr><td>Deep Research</td><td>Full 5-agent pipeline</td><td>Enabled (multi-iteration)</td><td>Complex research, analysis</td></tr><tr><td>Rapid Execution</td><td>Simplified pipeline</td><td>Disabled or limited</td><td>Quick tasks, simple queries</td></tr></tbody></table><p><strong>Why it matters</strong>: Most agent frameworks offer a single execution path. The dual-mode approach lets users trade thoroughness for speed explicitly, rather than relying on the agent to self-calibrate. This is a pragmatic design that acknowledges not every task needs a full multi-agent pipeline.</p><h2 id="_2-linear-pipeline-with-observation-feedback" tabindex="-1">2. Linear Pipeline with Observation Feedback <a class="header-anchor" href="#_2-linear-pipeline-with-observation-feedback" aria-label="Permalink to &quot;2. Linear Pipeline with Observation Feedback&quot;">​</a></h2><p>Unlike graph-based agent orchestration (e.g., LangGraph) or tree-based approaches, SageAgent uses a <strong>simple linear pipeline</strong> with exactly one feedback edge:</p>',7)),(t(),d(p,null,{default:n(()=>[c(i,{id:"mermaid-66",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22Analysis%22%5D%20--%3E%20P%5B%22Planning%22%5D%20--%3E%20E%5B%22Execution%22%5D%20--%3E%20O%5B%22Observation%22%5D%0A%20%20%20%20O%20--%20%22loop%22%20--%3E%20P%0A%20%20%20%20O%20--%20%22done%22%20--%3E%20S%5B%22Summary%22%5D%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p><strong>Why it matters</strong>: This is intentionally simple. The single feedback point (Observation → Planning) avoids the complexity of arbitrary agent-to-agent communication while still enabling iterative refinement. It&#39;s easier to debug, reason about, and explain than a full agent graph.</p><h2 id="_3-mcp-native-tool-architecture" tabindex="-1">3. MCP-Native Tool Architecture <a class="header-anchor" href="#_3-mcp-native-tool-architecture" aria-label="Permalink to &quot;3. MCP-Native Tool Architecture&quot;">​</a></h2><p>SageAgent builds MCP support into the core ToolManager rather than treating it as an add-on. Both stdio and SSE transport modes are supported, with configuration via <code>mcp_setting.json</code>.</p><p><strong>Why it matters</strong>: Many agent frameworks bolt on MCP support after the fact. SageAgent&#39;s approach of having ToolManager natively handle both local and MCP tools means external tools are first-class citizens, not second-class wrappers.</p><h2 id="_4-specialized-agent-roles" tabindex="-1">4. Specialized Agent Roles <a class="header-anchor" href="#_4-specialized-agent-roles" aria-label="Permalink to &quot;4. Specialized Agent Roles&quot;">​</a></h2><p>Each pipeline stage has a dedicated agent class rather than using a single general-purpose agent with different prompts:</p><ul><li><code>TaskAnalysisAgent</code> — not just &quot;understand the task&quot; but a separate class</li><li><code>PlanningAgent</code> — dedicated planner</li><li><code>ExecutorAgent</code> — dedicated executor with tool access</li><li><code>ObservationAgent</code> — dedicated evaluator</li><li><code>TaskSummaryAgent</code> — dedicated summarizer</li></ul><p><strong>Why it matters</strong>: This enforces separation of concerns at the code level, not just the prompt level. Each agent can have specialized logic, different model configurations, or different tool access. The tradeoff is more code and classes to maintain.</p><h2 id="_5-professional-agents-concept" tabindex="-1">5. Professional Agents Concept <a class="header-anchor" href="#_5-professional-agents-concept" aria-label="Permalink to &quot;5. Professional Agents Concept&quot;">​</a></h2><p>The <code>professional_agents/</code> directory and roadmap item suggest a plugin architecture for domain-specialized agents. These would presumably slot into the pipeline for specific task domains (e.g., code analysis, data science).</p><p><strong>Why it matters</strong>: This is a forward-looking extensibility pattern. While not yet fully implemented, it signals an intent to move beyond generic agents toward domain-specialized ones — similar to how IDEs have language-specific plugins.</p><h2 id="_6-thinking-message-type" tabindex="-1">6. Thinking Message Type <a class="header-anchor" href="#_6-thinking-message-type" aria-label="Permalink to &quot;6. Thinking Message Type&quot;">​</a></h2><p>The explicit <code>thinking</code> message type (alongside <code>normal</code>) separates chain-of-thought reasoning from actionable output at the protocol level.</p><p><strong>Why it matters</strong>: This is a clean abstraction that enables UIs to show/hide reasoning traces, logging systems to filter by message type, and downstream agents to distinguish between conclusions and deliberation.</p><h2 id="comparison-to-other-frameworks" tabindex="-1">Comparison to Other Frameworks <a class="header-anchor" href="#comparison-to-other-frameworks" aria-label="Permalink to &quot;Comparison to Other Frameworks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>SageAgent</th><th>LangGraph</th><th>CrewAI</th></tr></thead><tbody><tr><td>Orchestration</td><td>Linear pipeline</td><td>Arbitrary graph</td><td>Role-based crew</td></tr><tr><td>Feedback</td><td>Single loop point</td><td>Any edge</td><td>Inter-agent chat</td></tr><tr><td>Tool integration</td><td>MCP-native</td><td>Tool abstraction</td><td>Tool abstraction</td></tr><tr><td>Execution modes</td><td>Dual (Deep/Rapid)</td><td>Single</td><td>Single</td></tr><tr><td>Agent identity</td><td>Class per role</td><td>Node per step</td><td>Agent per role</td></tr></tbody></table><hr><p><em>Tier 3 analysis — patterns identified from public architecture and README.</em></p>',18))])}const A=o(h,[["render",g]]);export{k as __pageData,A as default};
